mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER( ORDER BY
A1.insertDt DESC
CAST(A1.${sortColumn} AS INTEGER) ${order}
A1.${sortColumn} ${order}
) AS PAGEINDEX FROM ( SELECT info.*, insertUser.USER_NM AS insertUserNm, updateUser.USER_NM AS updateUserNm, ecnInsert.USER_NM AS ecnUserNm FROM (
SELECT info.BUSINESS_TYPE_CD AS businessTypeCd, FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm, info.SW_TYPE_CD AS swTypeCd, FN_GET_CD_NM('swClassCd1', info.SW_TYPE_CD, 'ko') AS swTypeNm, info.DISTRIBUTE_TYPE_CD AS distributeTypeCd, -- FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm, info.DISTRIBUTE_TYPE_NAME AS distributeTypeNm, info.SW_NO AS swNo, info.SW_NM AS swNm, info.SW_VERSION_No AS swVersionNo, info.OBJECT_ID AS objectId, info.REV_NO AS revNo, info.INSERT_UID AS insertUid, info.UPDATE_UID AS updateUid, info.ecn_insert_uid AS ecn_insert_uid, info.REGISTER_USER AS registerUser, info.INSERT_DEPT_NM AS insertDeptNm, info.STD_GAPP_DT AS stdGappDt, info.CHANGE_GAPP_DT AS changeGappDt, info.ECN_NO AS ecnNo, info.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm, info.PROTECT_YN AS protectYn, info.PROTECT_YN AS protectYnView, info.UPDATE_DT AS updateDt, info.INSERT_DT AS insertDt, info.CREATE_DT AS createDt, info.CCBDATE AS ccbDate, info.APPROVER AS approver, info.REVIEWERUSER AS reviewerUser, COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus, CASE WHEN info.STATUS = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.APPROVER), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.APPROVER, ' ', ''), ',') AS ap(token) WHERE ap.token <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.REVIEWERUSER), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.REVIEWERUSER, ' ', ''), ',') AS rv(token) WHERE rv.token <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status, info.INTERFACE_DT AS interfaceDt, info.PRODUCT_CD AS productCd, COALESCE(info.PRODUCT_CD, '') AS productNm, (SELECT COUNT(*) FROM DOCS_SW_FILE swFile WHERE swFile.OBJECT_ID = info.OBJECT_ID) AS fileCount, DENSE_RANK() OVER (PARTITION BY SW_NO ORDER BY REV_NO DESC) AS rnk, fileInfo.FILE_NO AS fileNo, fileInfo.ORG_FILE_NM AS fileViewNm, fileInfo.FILE_NM AS fileNm, fileInfo.FILE_SIZE AS fileSize, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_PATH_NM AS filePath, info.VALID_TYPE AS validType FROM DOCS_SW_FILE fileInfo JOIN DOCS_SW info ON fileInfo.OBJECT_ID = info.OBJECT_ID
SELECT info.BUSINESS_TYPE_CD AS businessTypeCd, FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm, info.SW_TYPE_CD AS swTypeCd, FN_GET_CD_NM('swClassCd1', info.SW_TYPE_CD, 'ko') AS swTypeNm, info.DISTRIBUTE_TYPE_CD AS distributeTypeCd, -- FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm, info.DISTRIBUTE_TYPE_NAME AS distributeTypeNm, info.SW_NO AS swNo, info.SW_NM AS swNm, info.SW_VERSION_No AS swVersionNo, info.OBJECT_ID AS objectId, info.REV_NO AS revNo, info.INSERT_UID AS insertUid, info.UPDATE_UID AS updateUid, info.ecn_insert_uid AS ecn_insert_uid, info.REGISTER_USER AS registerUser, info.INSERT_DEPT_NM AS insertDeptNm, info.STD_GAPP_DT AS stdGappDt, info.CHANGE_GAPP_DT AS changeGappDt, info.ECN_NO AS ecnNo, info.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm, info.PROTECT_YN AS protectYn, info.PROTECT_YN AS protectYnView, info.UPDATE_DT AS updateDt, info.INSERT_DT AS insertDt, info.CREATE_DT AS createDt, info.CCBDATE AS ccbDate, info.APPROVER AS approver, info.REVIEWERUSER AS reviewerUser, COALESCE(fileInfo.PROCESSING_STATUS, '') AS processingStatus, CASE WHEN info.STATUS = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.APPROVER), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.APPROVER, ' ', ''), ',') AS ap(token) WHERE ap.token <> '' AND POSITION(',' || ap.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) AND ( COALESCE(NULLIF(TRIM(info.REVIEWERUSER), ''), '') = '' OR NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.REVIEWERUSER, ' ', ''), ',') AS rv(token) WHERE rv.token <> '' AND POSITION(',' || rv.token || ',' IN ',' || REPLACE(COALESCE(info.APPROVED_USERS, info.STATUS, ''), ' ', '') || ',') = 0 ) ) THEN '승인완료' ELSE '승인진행중' END AS status, info.INTERFACE_DT AS interfaceDt, info.PRODUCT_CD AS productCd, COALESCE(info.PRODUCT_CD, '') AS productNm, (SELECT COUNT(*) FROM DOCS_SW_FILE swFile WHERE swFile.OBJECT_ID = info.OBJECT_ID) AS fileCount, fileInfo.FILE_NO AS fileNo, fileInfo.ORG_FILE_NM AS fileViewNm, fileInfo.FILE_NM AS fileNm, fileInfo.FILE_SIZE AS fileSize, fileInfo.ORG_FILE_NM AS orgFileNm, fileInfo.FILE_PATH_NM AS filePath, info.VALID_TYPE AS validType FROM DOCS_SW_FILE fileInfo JOIN DOCS_SW info ON fileInfo.OBJECT_ID = info.OBJECT_ID
WHERE 1=1 AND info.DELETED_YN = 'N'
AND BUSINESS_TYPE_CD = #{businessTypeCd}
AND BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND SW_NO = UPPER(TRIM(#{swNo}))
AND SW_NO LIKE '%' || UPPER(TRIM(#{swNo})) || '%'
AND EXISTS ( SELECT 1 FROM DOCS_SW_TREE node JOIN DOCS_SW_TREE selectedNode ON selectedNode.TREE_CD IN
#{treeCd}
WHERE node.TREE_CD = info.TREE_CD AND node.TREE_PATH LIKE selectedNode.TREE_PATH || '%' )
AND info.SW_NM LIKE '%' || #{swNm} || '%'
AND ( fileInfo.ORG_FILE_NM LIKE '%' || #{fileViewNm} || '%' OR fileInfo.FILE_NM LIKE '%' || #{fileViewNm} || '%' )
AND fileInfo.FILE_NM LIKE '%' || #{fileNm} || '%'
AND SW_TYPE_CD LIKE '%' || #{swTypeCd} || '%'
AND info.DISTRIBUTE_TYPE_CD = #{distributeTypeCd}
AND ECN_NO LIKE '%' || UPPER(TRIM(#{ecnNo})) || '%'
AND PRODUCT_CD = #{productCd}
AND INSERT_UID = #{insertUid}
AND VALID_TYPE IS NULL
AND VALID_TYPE = 'N'
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
AND (
(SW_NO LIKE '%' || UPPER(TRIM(#{swInfo.swNo})) || '%')
)
AND (
(SW_NO = UPPER(TRIM(#{swInfo.swNo})))
)
) info LEFT JOIN DOCS_USER insertUser ON insertUser.USER_ID = info.insertUid LEFT JOIN DOCS_USER updateUser ON updateUser.USER_ID = info.updateUid LEFT JOIN DOCS_USER ecnInsert ON ecnInsert.USER_ID = info.ecn_insert_uid
WHERE rnk = 1
ORDER BY insertDT DESC, swNo, revNo DESC, fileNo
ORDER BY ${sortColumn} ${order}
) A1 ) B1 WHERE 1=1
AND PAGEINDEX <= #{end}
AND PAGEINDEX >= #{start}

SELECT OBJECT_ID
FROM DOCS_SW_FILE
WHERE OBJECT_ID = #{objectId}

mapper.update:
UPDATE DOCS_SW SET
DELETED_YN = 'Y'
WHERE OBJECT_ID = #{objectId}

mapper.select:
SELECT mainFile.OBJECT_ID AS "objectId", CAST(mainFile.FILE_NO AS TEXT) AS "fileNo", mainFile.ORG_FILE_NM AS "orgFileNm", mainFile.FILE_PATH_NM AS "filePath" FROM DOCS_SW_FILE mainFile JOIN DOCS_SW sw ON sw.OBJECT_ID = mainFile.OBJECT_ID WHERE mainFile.OBJECT_ID = #{objectId} AND COALESCE(sw.DELETED_YN, 'N') = 'N' AND CAST(mainFile.FILE_NO AS INTEGER) = 1
AND CAST(mainFile.FILE_NO AS TEXT) = #{fileNo}
UNION ALL SELECT subFile.OBJECT_ID AS "objectId", CAST(subFile.FILE_NO AS TEXT) AS "fileNo", subFile.ORG_FILE_NM AS "orgFileNm", subFile.FILE_PATH_NM AS "filePath" FROM DOCS_SW_SUB_FILE subFile WHERE (subFile.OBJECT_ID = #{objectId} OR subFile.PARENT_OBJECT_ID = #{objectId}) AND COALESCE(subFile.USE_YN, 'Y') = 'Y'
AND CAST(subFile.FILE_NO AS TEXT) = #{fileNo}
LIMIT 1
